479	// ValidateForExecuteLoopViaService is the production replacement for
480	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
481	// will pick at claim time). When harness is specified it confirms the harness
482	// exists in the service registry and (when model is set) attempts a
483	// ResolveRoute pre-flight.
484	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
485		if harnessName == "" {
486			return nil
487		}
488		if ctx == nil {
489			ctx = context.Background()
490		}
491		svc, err := resolveService(workDir)
492		if err != nil {
493			return fmt.Errorf("agent: build service: %w", err)
494		}
495		infos, err := svc.ListHarnesses(ctx)
496		if err != nil {
497			return fmt.Errorf("agent: list harnesses: %w", err)
498		}
499		found := false
500		for _, info := range infos {
501			if info.Name == harnessName {
502				found = true
503				if !info.Available {
504					return fmt.Errorf("agent: harness %s not available", harnessName)
505				}
506				break
507			}
508		}
509		if !found {
510			return fmt.Errorf("agent: unknown harness: %s", harnessName)
511		}
512	
513		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
514		// model is provided and provider/model-ref are not set.
515		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
516			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
517				Model:    model,
518				Harness:  fizeauHarness(harnessName),
519				Provider: provider,
520			}); err != nil {
521				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
522			}
523		}
524		return nil
525	}
